"use strict";(self.webpackChunkheiman_wiki_public=self.webpackChunkheiman_wiki_public||[]).push([["6750"],{926(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"welcome","metadata":{"permalink":"/heiman-wiki-public/nl/blog/welcome","source":"@site/i18n/nl/docusaurus-plugin-content-blog/2021-08-26-welcome/index.mdx","title":"Welkom bij de Heiman Technology Wiki","description":"Welkom bij de Heiman Technology Wiki! Dit is de offici\xeble kennisbank van Heiman Technology, met productdocumentatie, technische oplossingen, industrietrends en bedrijfsnieuws.","date":"2021-08-26T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/nl/blog/tags/heiman","description":"Nieuws over Heiman Technology"}],"readingTime":0.67,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/nl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"welcome","title":"Welkom bij de Heiman Technology Wiki","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"nextItem":{"title":"Heiman Matter Protocol Slimme Rookmelder Officieel Gelanceerd","permalink":"/heiman-wiki-public/nl/blog/mdx-blog-post"}},"content":"Welkom bij de Heiman Technology Wiki! Dit is de offici\xeble kennisbank van Heiman Technology, met productdocumentatie, technische oplossingen, industrietrends en bedrijfsnieuws.\\n\\n{/* truncate */}\\n\\n## Over Deze Site\\n\\nDe Heiman Technology Wiki biedt partners, ontwikkelaars en klanten een one-stop technische bron om snel het volgende te ontdekken:\\n\\n- **Productencentrum** \u2014 Volledige serie producten voor Slimme Brandveiligheid, Slimme Gasveiligheid, Slimme Ouderenzorg en Slimme Sensoren\\n- **Oplossingen** \u2014 Complete slimme beveiligingsoplossingen op industrieniveau\\n- **Technische Documentatie** \u2014 API-integratiegidsen, SDK-gebruiksinstructies, installatie- en implementatiehandleidingen\\n- **Industrie-inzichten** \u2014 Trends en beleidsinterpretaties in de slimme beveiligingssector\\n\\n## Snelle Navigatie\\n\\n- Bekijk [Producten & Oplossingen](/docs/tutorial-basics/create-a-page) voor het Heiman-productaanbod\\n- Lees [Bedrijfsintroductie](/docs/intro) om de ontwikkelingsgeschiedenis van Heiman te ontdekken\\n- Bezoek [Heiman Website](https://www.heiman.com.cn) voor meer informatie\\n\\nBij vragen kunt u de klantenservice bellen op **400-8959-500** of contact opnemen met online klantenservice."},{"id":"mdx-blog-post","metadata":{"permalink":"/heiman-wiki-public/nl/blog/mdx-blog-post","source":"@site/i18n/nl/docusaurus-plugin-content-blog/2021-08-01-mdx-blog-post.mdx","title":"Heiman Matter Protocol Slimme Rookmelder Officieel Gelanceerd","description":"Heiman Technology\'s nieuwste Matter protocol slimme rookmelder HS1SA-M is officieel gelanceerd. Dit is een van de eerste rookmelders in de industrie die Matter 1.2-certificering heeft ontvangen.","date":"2021-08-01T00:00:00.000Z","tags":[{"inline":false,"label":"Matter","permalink":"/heiman-wiki-public/nl/blog/tags/matter","description":"Matter-protocol gerelateerde inhoud"},{"inline":false,"label":"Slimme Brandveiligheid","permalink":"/heiman-wiki-public/nl/blog/tags/smart-fire","description":"Slimme brandveiligheidsproducten en oplossingen"}],"readingTime":0.65,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/nl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"mdx-blog-post","title":"Heiman Matter Protocol Slimme Rookmelder Officieel Gelanceerd","authors":["heiman"],"tags":["matter","smart-fire"]},"unlisted":false,"prevItem":{"title":"Welkom bij de Heiman Technology Wiki","permalink":"/heiman-wiki-public/nl/blog/welcome"},"nextItem":{"title":"Terugblik op de Ontwikkelingsgeschiedenis van Heiman Technology","permalink":"/heiman-wiki-public/nl/blog/long-blog-post"}},"content":"Heiman Technology\'s nieuwste Matter protocol slimme rookmelder HS1SA-M is officieel gelanceerd. Dit is een van de eerste rookmelders in de industrie die Matter 1.2-certificering heeft ontvangen.\\n\\n{/* truncate */}\\n\\n:::tip\\n\\nHS1SA-M ondersteunt Apple HomeKit, Amazon Alexa, Google Home en Samsung SmartThings \u2014 de vier grootste smart home-ecosystemen.\\n\\n:::\\n\\n## Kernfuncties\\n\\n- **Matter 1.2-certificering** \u2014 Realiseert cross-brand, cross-ecosysteem interconnectiviteit\\n- **Optische rookdetectie** \u2014 Snelle respons op verschillende soorten brandrook\\n- **Spraakalarmmelding** \u2014 Meerdere spraakopties, duidelijke waarschuwing bij gevaar\\n- **Zelftestfunctie** \u2014 Periodieke zelftest om normale werking te garanderen\\n- **Melding op afstand** \u2014 Realtime pushmeldingen naar telefoon APP\\n\\n## Compatibiliteit\\n\\nHS1SA-M kan naadloos worden ge\xefntegreerd met gangbare smart home-platforms. Gebruikers hebben geen extra gateway nodig en kunnen het apparaat direct via hun telefoon bedienen en beheren.\\n\\nBezoek [Productencentrum](/docs/tutorial-basics/create-a-page) voor meer informatie."},{"id":"long-blog-post","metadata":{"permalink":"/heiman-wiki-public/nl/blog/long-blog-post","source":"@site/i18n/nl/docusaurus-plugin-content-blog/2019-05-29-long-blog-post.mdx","title":"Terugblik op de Ontwikkelingsgeschiedenis van Heiman Technology","description":"Vanaf de oprichting in 2005 heeft Heiman Technology meer dan 20 jaar ontwikkeling doorgemaakt. Dit artikel neemt u mee langs de belangrijke mijlpalen van Heiman.","date":"2019-05-29T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/nl/blog/tags/heiman","description":"Nieuws over Heiman Technology"}],"readingTime":1.15,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/nl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"long-blog-post","title":"Terugblik op de Ontwikkelingsgeschiedenis van Heiman Technology","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Heiman Matter Protocol Slimme Rookmelder Officieel Gelanceerd","permalink":"/heiman-wiki-public/nl/blog/mdx-blog-post"},"nextItem":{"title":"Heiman Technology Ontvangt Nationale \\"Kleine Reus\\" Ondernemingserkenning","permalink":"/heiman-wiki-public/nl/blog/first-blog-post"}},"content":"Vanaf de oprichting in 2005 heeft Heiman Technology meer dan 20 jaar ontwikkeling doorgemaakt. Dit artikel neemt u mee langs de belangrijke mijlpalen van Heiman.\\n\\n{/* truncate */}\\n\\n## 2005 - Bedrijfsoprichting\\n\\nShenzhen Heiman Technology Co., Ltd. wordt officieel opgericht en betreedt de beveiligingssensorindustrie.\\n\\n## 2006 - Internationale Start\\n\\nMeerdere producten behalen CE-certificering van de Europese Unie en er wordt samenwerking gestart met China Mobile.\\n\\n## 2011 - Internationale Certificeringsdoorbraak\\n\\nMeerdere producten behalen EU EN54-7 en EN14604-certificering, wat aangeeft dat de productkwaliteit internationaal geavanceerd niveau heeft bereikt.\\n\\n## 2012 - Transformatie naar Slimme Woningen\\n\\nHet smart home-project wordt volledig gelanceerd. Heiman transformeert naar een bedrijf dat zich richt op onderzoek, productie en verkoop van smart home-producten.\\n\\n## 2017 - Belangrijke Doorbraak\\n\\n- Ontwikkeling van de eerste NB-IoT rookmelder in China\\n- Ontvangt 2 Duitse Red Dot Design Awards\\n- Behaalt MFi-certificering en verkrijgt Apple-fabrikantkwalificatie\\n\\n## 2020 - Kapitaalinjectie\\n\\nVoltooit Series A-financiering met Shenzhen Hi-Tech Investment Group als investeerder. Ontvangt de titel \\"Guangdong Gespecialiseerde en Nieuwe MKB-onderneming\\".\\n\\n## 2022 - Nationale Erkenning\\n\\nWordt erkend als nationale Gespecialiseerde en Nieuwe \\"Kleine Reus\\" onderneming. K1-serie wint Duitse Red Dot Design Award.\\n\\n## 2023 - Internationale Normleiding\\n\\nHeiman-testlaboratorium ontvangt offici\xeble CNAS-certificering. Rookmelders en koolmonoxidemelders zijn de eerste die Matter 1.2-certificering ontvangen.\\n\\n## 2024 - Heden\\n\\nVoortdurende innovatie, verdieping in vier kerngebieden: Slimme Brandveiligheid, Slimme Gasveiligheid, Slimme Ouderenzorg en Slimme Sensoren. Levert hoogwaardige producten en diensten aan klanten in 100+ landen wereldwijd."},{"id":"first-blog-post","metadata":{"permalink":"/heiman-wiki-public/nl/blog/first-blog-post","source":"@site/i18n/nl/docusaurus-plugin-content-blog/2019-05-28-first-blog-post.mdx","title":"Heiman Technology Ontvangt Nationale \\"Kleine Reus\\" Ondernemingserkenning","description":"In 2022 werd Heiman Technology, dankzij zijn diepgaande technische kennis en innovatievermogen in slimme sensoren, officieel erkend als een nationale Gespecialiseerde en Nieuwe \\"Kleine Reus\\" onderneming.","date":"2019-05-28T00:00:00.000Z","tags":[{"inline":false,"label":"Heiman Technology","permalink":"/heiman-wiki-public/nl/blog/tags/heiman","description":"Nieuws over Heiman Technology"}],"readingTime":0.45,"hasTruncateMarker":true,"authors":[{"name":"Heiman Technology","title":"Shenzhen Heiman Technology Co., Ltd.","url":"https://www.heiman.com.cn","page":{"permalink":"/heiman-wiki-public/nl/blog/authors/heiman"},"socials":{"x":"https://x.com/heimantech","linkedin":"https://www.linkedin.com/in/heimantech/"},"imageURL":"https://www.heiman.com.cn/favicon.ico","key":"heiman"}],"frontMatter":{"slug":"first-blog-post","title":"Heiman Technology Ontvangt Nationale \\"Kleine Reus\\" Ondernemingserkenning","authors":["heiman"],"tags":["heiman"]},"unlisted":false,"prevItem":{"title":"Terugblik op de Ontwikkelingsgeschiedenis van Heiman Technology","permalink":"/heiman-wiki-public/nl/blog/long-blog-post"}},"content":"In 2022 werd Heiman Technology, dankzij zijn diepgaande technische kennis en innovatievermogen in slimme sensoren, officieel erkend als een nationale Gespecialiseerde en Nieuwe \\"Kleine Reus\\" onderneming.\\n\\n{/* truncate */}\\n\\nDeze nationale erkenning is een hoge waardering voor Heiman Technology op het gebied van specialisatie, verfijning, karakterisering en vernieuwing. Heiman zal zich blijven verdiepen in slimme brandveiligheid, slimme gasveiligheid, slimme ouderenzorg en slimme sensoren, en klanten blijven voorzien van hoogwaardige producten en diensten.\\n\\nEerder had Heiman Technology al meerdere gezaghebbende kwalificaties verkregen, waaronder Nationale Hightech-onderneming en Guangdong Gespecialiseerde en Nieuwe MKB-onderneming."}]}}')}}]);